    User user1 = {"Alice", 30, "alice@example.com"};
    system.addUser("alice", user1);

    User* userProfile = system.getUserProfile("alice");
    if (userProfile != nullptr) {
        std::cout << "Name: " << userProfile->name << std::endl;
        std::cout << "Age: " << userProfile->age << std::endl;
        std::cout << "Email: " << userProfile->email << std::endl;
    } else {
        std::cout << "User not found." << std::endl;
    }

    return 0;
